    /// <summary>
    /// Look up a technology's game-data metadata by its ID.
    /// Returns null if the tech ID is not in the catalog.
    /// </summary>
    public static TechCatalogEntry? GetTechCatalogEntry(string techId)
    {
        if (_techCatalog.TryGetValue(techId, out var entry)) return entry;
        // Try with/without ^ prefix
        if (techId.StartsWith("^") && _techCatalog.TryGetValue(techId[1..], out entry)) return entry;
        if (!techId.StartsWith("^") && _techCatalog.TryGetValue("^" + techId, out entry)) return entry;
        return null;
    }
